// The media library — raw footage plus everything generated by the tools,
// grouped by category. Mock data stands in until wired to the Resolve Media
// Pool + real generation jobs.

export type AssetKind = 'image' | 'video' | 'audio'

export interface Asset {
  id: string
  name: string
  category: string
  kind: AssetKind
  meta: string // timecode, duration, or resolution
}

export interface LibraryCategory {
  id: string
  label: string
  color: string
  kind: AssetKind
  assets: Asset[]
}

