export const LIBRARY_COUNT = LIBRARY.reduce((n, c) => n + c.assets.length, 0)

export function searchLibrary(query: string): LibraryCategory[] {
  const q = query.trim().toLowerCase()
  if (!q) return LIBRARY
  return LIBRARY.map((cat) => ({
    ...cat,
    assets: cat.assets.filter(
      (a) => a.name.toLowerCase().includes(q) || a.category.toLowerCase().includes(q),
    ),
  })).filter((cat) => cat.assets.length > 0)
}
